app8.get(async (c) => {
  const db = createDb(c.env.DB);
  const postId = c.req.param("id");
  if (!postId) return c.json({ error: "Missing post id" }, 400);
  try {
    const postComments = await db.select({
      id: comments.id,
      content: comments.content,
      authorId: comments.authorId,
      postId: comments.postId,
      createdAt: comments.createdAt,
      updatedAt: comments.updatedAt,
      upvotes: comments.upvotes,
      downvotes: comments.downvotes,
      author: {
        id: users.id,
        username: users.username,
        email: users.email
      }
    }).from(comments).leftJoin(users, eq(comments.authorId, users.id)).where(eq(comments.postId, postId));
    const sessionCookie = getCookie(c, "session");
    let userVotes = {};
    if (sessionCookie) {
      const userId = await getUserIdFromSession(sessionCookie, db);
      if (userId) {
        const commentIds = postComments.map((comment) => comment.id);
        if (commentIds.length > 0) {
          const userVoteResults = await db.select({
            commentId: votes.commentId,
            value: votes.value
          }).from(votes).where(
            and(
              eq(votes.userId, userId),
              eq(votes.voteType, "comment")
            )
          );
          userVotes = userVoteResults.reduce((acc, vote) => {
            if (vote.commentId) {
              acc[vote.commentId] = vote.value;
            }
            return acc;
          }, {});
        }
      }
    }
    return c.json({
      comments: postComments,
      userVotes
    });
  } catch (error3) {
    console.error("Error fetching comments:", error3);
    return c.json({ error: "Failed to fetch comments" }, 500);
  }
});
